void WritePoint3(pb::Point3F* message, const XMFLOAT3& point) {
    message->set_x(point.x);
    message->set_y(point.y);
    message->set_z(point.z);
}

XMFLOAT3 ReadPoint3(const pb::Point3F& message) {
    return XMFLOAT3(message.x(), message.y(), message.z());
}

void WriteColor4(pb::Color4F* message, const XMHALF4& color) {
    message->set_r(DirectX::PackedVector::XMConvertHalfToFloat(color.x));
    message->set_g(DirectX::PackedVector::XMConvertHalfToFloat(color.y));
    message->set_b(DirectX::PackedVector::XMConvertHalfToFloat(color.z));
    message->set_a(DirectX::PackedVector::XMConvertHalfToFloat(color.w));
}

XMHALF4 ReadColor4(const pb::Color4F& message) {
    return XMHALF4(message.r(), message.g(), message.b(), message.a());
}

XMHALF4 DefaultColor4() {
    return XMHALF4(0.8f, 0.8f, 0.8f, 1.0f);
}

std::string FixedCStringToString(const char* value, size_t capacity) {
    if (!value || capacity == 0) return {};
    const void* terminator = std::memchr(value, '\0', capacity);
    const size_t length = terminator
        ? static_cast<const char*>(terminator) - value
        : capacity;
    return std::string(value, value + length);
}

void CopyStringToFixedCString(const std::string& value, char* target, size_t capacity) {
    if (!target || capacity == 0) return;
    std::memset(target, 0, capacity);
    const size_t copyLength = (std::min)(value.size(), capacity - 1);
    if (copyLength > 0) {
        std::memcpy(target, value.data(), copyLength);
    }
}

template <typename Message>
bool SerializeMessage(const Message& message, std::vector<uint8_t>& payload, std::string* errorMessage) {
    std::string bytes;
    if (!message.SerializeToString(&bytes)) {
        SetError(errorMessage, "Could not serialize protobuf payload.");
        return false;
    }

    payload.assign(bytes.begin(), bytes.end());
    return true;
}

template <typename Message>
bool ParseMessage(const std::vector<uint8_t>& payload, Message& message) {
    if (payload.size() > static_cast<size_t>((std::numeric_limits<int>::max)())) {
        return false;
    }

    const void* data = payload.empty()
        ? static_cast<const void*>("")
        : static_cast<const void*>(payload.data());
    return message.ParseFromArray(data, static_cast<int>(payload.size()));
}

