bool DecodePyramid(const std::vector<uint8_t>& payload, PYRAMID& object) {
    pb::Pyramid message;
    if (!ParseMessage(payload, message)) return false;

    object.vertices.clear();
    object.vertices.reserve(message.vertices_size());
    for (int i = 0; i < message.vertices_size(); ++i) {
        object.vertices.push_back(ReadPoint3(message.vertices(i)));
    }

    object.colors.clear();
    object.colors.reserve(message.colors_size());
    for (int i = 0; i < message.colors_size(); ++i) {
        object.colors.push_back(ReadColor4(message.colors(i)));
    }
    if (object.colors.empty()) object.colors.push_back(DefaultColor4());

    return object.vertices.size() >= 4;
}

bool DecodeCuboid(const std::vector<uint8_t>& payload, CUBOID& object) {
    pb::Cuboid message;
    if (!ParseMessage(payload, message)) return false;

    object.vertices.clear();
    object.vertices.reserve(message.vertices_size());
    for (int i = 0; i < message.vertices_size(); ++i) {
        object.vertices.push_back(ReadPoint3(message.vertices(i)));
    }
    object.colors = message.has_color() ? ReadColor4(message.color()) : DefaultColor4();
    return object.vertices.size() >= 8;
}

